import { readFileSync, writeFileSync, mkdirSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const root = join(dirname(fileURLToPath(import.meta.url)), '..')
const uri = rel => 'data:image/png;base64,' + readFileSync(join(root, rel)).toString('base64')

const LOGO_PNG = uri('src/lib/report/assets/dk-logo.png')       // 229x48 (ratio 4.77)
const WATERMARK_PNG = uri('src/lib/report/assets/dk-watermark.png') // 450x622 (ratio 0.723)

const out =
  '// AUTO-GENERATED by scripts/gen-report-assets.mjs — DO NOT EDIT.\n' +
  '// 원본 PNG 변경 시 `node scripts/gen-report-assets.mjs` 재실행 후 커밋.\n' +
  `export const LOGO_PNG = ${JSON.stringify(LOGO_PNG)}\n` +
  `export const WATERMARK_PNG = ${JSON.stringify(WATERMARK_PNG)}\n`

mkdirSync(join(root, 'src/lib/report/assets'), { recursive: true })
writeFileSync(join(root, 'src/lib/report/assets/reportImages.ts'), out)
console.log('wrote src/lib/report/assets/reportImages.ts (%d + %d bytes b64)', LOGO_PNG.length, WATERMARK_PNG.length)
